-- CNB Primaria - Expresión Artística - Quinto y Sexto Grado
-- Fuentes: .../Dosificación_de_los_aprendizajes_-_Área_de_Expresión_Artística_-_{Grado}

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
-- Quinto Grado
('Quinto Grado', 'Expresión Artística', '1. Utiliza los lenguajes artísticos en planteamientos creativos para la resolución de problemas.', ARRAY['1.1. Manifiesta comprensión del significado de los símbolos utilizados en la lecto-escritura musical.', '1.2. Establece la diferencia entre los colores existentes en la naturaleza y los producidos por el ser humano.', '1.3. Relaciona la percepción visual y auditiva de signos y efectos escénicos con elementos de la cotidianeidad.']),
('Quinto Grado', 'Expresión Artística', '2. Utiliza los lenguajes artísticos para establecer relación entre la expresión de emociones e ideas y la realidad circundante.', ARRAY['2.1. Asocia ritmos y sonidos con elementos del entorno circundante.', '2.2. Interpreta la intencionalidad del autor al analizar el uso de la forma, el color y la textura.']),
('Quinto Grado', 'Expresión Artística', '3. Utiliza técnicas de las diferentes artes y los saberes tradicionales de su comunidad en la elaboración de proyectos específicos.', ARRAY['3.1. Participa en actividades colectivas de canto y ejecución instrumental.', '3.2. Aplica técnicas que evidencian conocimiento del efecto de la luz sobre el color y del manejo de diversos materiales de su comunidad en la elaboración de proyectos escolares.', '3.3. Asocia el movimiento, el ritmo y el espacio en el montaje de coreografías.']),
('Quinto Grado', 'Expresión Artística', '4. Identifica diferentes opciones para impulsar técnicas utilizadas en la creación y producción artísticas.', ARRAY['4.1. Utiliza diferentes medios en la divulgación de eventos relacionados con la tradición musical de su comunidad.', '4.2. Utiliza diferentes medios en la divulgación de las técnicas de producción de la plástica y los textiles propios de su comunidad.', '4.3. Utiliza diferentes medios para la divulgación de eventos propios de la tradición oral de su comunidad.']),

-- Sexto Grado
('Sexto Grado', 'Expresión Artística', '1. Relaciona los códigos de las disciplinas artísticas con los saberes tradicionales.', ARRAY['1.1. Utiliza la lecto-escritura musical en la interpretación de música tradicional o moderna.', '1.2. Utiliza el registro audiovisual (grabación) como recurso para analizar y valorar el trabajo artístico.']),
('Sexto Grado', 'Expresión Artística', '2. Utiliza los lenguajes artísticos para fortalecer la comunicación de emociones e ideas con otros y otras.', ARRAY['2.1. Describe los procesos de experimentación sonora en función de la música y de la comunicación.', '2.2. Utiliza un lenguaje iconográfico en el diseño de afiches, carteles y letreros.']),
('Sexto Grado', 'Expresión Artística', '3. Participa en la producción de proyectos artísticos, individuales y colectivos, como una forma de promover mejoras en su entorno inmediato.', ARRAY['3.1. Participa en conjuntos musicales y de danza que utilizan repertorios que reflejan la identidad nacional.', '3.2. Participa en proyectos artísticos que resaltan la importancia de las diferentes texturas para los débiles visuales.', '3.3. Participa en actividades de conservación del patrimonio cultural.']),
('Sexto Grado', 'Expresión Artística', '4. Relaciona conocimientos y técnicas de las distintas artes con los saberes tradicionales de su entorno en la creación y producción artística.', ARRAY['4.1. Participa en dramatizaciones de obras de su propia creación y de autores nacionales e internacionales.', '4.2. Participa en la producción de materiales audiovisuales con contenidos culturales de su comunidad y región.', '4.3. Participa en foros cuyo contenido enfoca los elementos de la tradición cultural de su comunidad.']);
